<span class="line">                <span class="token string single-quoted-string">&#39;maxMemory&#39;</span> <span class="token operator">=&gt;</span> <span class="token number">5</span> <span class="token operator">*</span> <span class="token class-name class-name-fully-qualified static-context"><span class="token punctuation">\\</span>Aedart<span class="token punctuation">\\</span>Contracts<span class="token punctuation">\\</span>Streams<span class="token punctuation">\\</span>BufferSizes</span><span class="token operator">::</span><span class="token constant">BUFFER_1MB</span><span class="token punctuation">,</span></span>
